struct OptionCard: View {
    let title: String
    let subtitle: String?
    let isSelected: Bool
    @Environment(\.accessibilityReduceMotion) private var reduceMotion

    var body: some View {
        VStack(alignment: .leading, spacing: FitTodaySpacing.xs) {
