// MARK: - Color Extension for Hex

extension Color {
    init(hex: String) {
        let hex = hex.trimmingCharacters(in: CharacterSet.alphanumerics.inverted)
        var int: UInt64 = 0
        Scanner(string: hex).scanHexInt64(&int)
        let a, r, g, b: UInt64
        switch hex.count {
        case 3: // RGB (12-bit)
            (a, r, g, b) = (255, (int >> 8) * 17, (int >> 4 & 0xF) * 17, (int & 0xF) * 17)
        case 6: // RGB (24-bit)
            (a, r, g, b) = (255, int >> 16, int >> 8 & 0xFF, int & 0xFF)
        case 8: // ARGB (32-bit)
            (a, r, g, b) = (int >> 24, int >> 16 & 0xFF, int >> 8 & 0xFF, int & 0xFF)
        default:
            (a, r, g, b) = (255, 0, 0, 0)
        }
        self.init(
            .sRGB,
            red: Double(r) / 255,
            green: Double(g) / 255,
            blue: Double(b) / 255,
            opacity: Double(a) / 255
        )
    }
}

// MARK: - Retro Pattern Views

struct RetroGridPattern: View {
    let lineColor: Color
    let spacing: CGFloat

    var body: some View {
        GeometryReader { geometry in
            Path { path in
                // Vertical lines
                let cols = Int(geometry.size.width / spacing)
                for i in 0...cols {
                    let x = CGFloat(i) * spacing
                    path.move(to: CGPoint(x: x, y: 0))
                    path.addLine(to: CGPoint(x: x, y: geometry.size.height))
                }

                // Horizontal lines
                let rows = Int(geometry.size.height / spacing)
                for i in 0...rows {
                    let y = CGFloat(i) * spacing
                    path.move(to: CGPoint(x: 0, y: y))
                    path.addLine(to: CGPoint(x: geometry.size.width, y: y))
                }
            }
            .stroke(lineColor, lineWidth: 1)
        }
        .allowsHitTesting(false)
        .accessibilityHidden(true)
    }
}

struct DiagonalStripesPattern: View {
    let color: Color
    let spacing: CGFloat
    let opacity: Double

    var body: some View {
        GeometryReader { geometry in
            Path { path in
                let diagonal = sqrt(pow(geometry.size.width, 2) + pow(geometry.size.height, 2))
                let stripes = Int(diagonal / spacing)

                for i in 0...stripes {
                    let offset = CGFloat(i) * spacing
                    path.move(to: CGPoint(x: -geometry.size.height + offset, y: 0))
                    path.addLine(to: CGPoint(x: offset, y: geometry.size.height))
