        colors: [Color(hex: "#FB7185"), Color(hex: "#F43F5E")],
        startPoint: .topLeading,
        endPoint: .bottomTrailing
    )

    // Endurance - Light Blue
    static let gradientEndurance = LinearGradient(
        colors: [Color(hex: "#60A5FA"), Color(hex: "#3B82F6")],
        startPoint: .topLeading,
        endPoint: .bottomTrailing
    )

    // Wellness - Green
