  1→//
  2→//  OnboardingFlowView.swift
  3→//  FitToday
  4→//
  5→//  Created by AI on 04/01/26.
  6→//  Refactored on 15/01/26 - Extracted components to separate files
  7→//
  8→
  9→import SwiftUI
 10→import Swinject
 11→
 12→struct OnboardingFlowView: View {
 13→    @Environment(AppRouter.self) private var router
 14→    @Environment(\.dependencyResolver) private var resolver
 15→    @State private var viewModel: OnboardingFlowViewModel
 16→    @State private var currentStep = 0
 17→    @State private var isSubmitting = false
 18→    @State private var showError = false
 19→
 20→    private let onFinished: () -> Void
 21→    private let isEditing: Bool
 22→
 23→    private var activeSteps: [SetupStep] { SetupStep.allCases }
 24→
 25→    init(resolver: Resolver, isEditing: Bool = false, onFinished: @escaping () -> Void) {
 26→        let repository = resolver.resolve(UserProfileRepository.self)!
 27→        let useCase = CreateOrUpdateProfileUseCase(repository: repository)
 28→        viewModel = OnboardingFlowViewModel(createProfileUseCase: useCase)
 29→        self.onFinished = onFinished
 30→        self.isEditing = isEditing
 31→    }
 32→
 33→    var body: some View {
 34→        setupView
 35→        .padding()
 36→        .background(
 37→            ZStack {
 38→                FitTodayColor.background
 39→                RetroGridPattern(lineColor: FitTodayColor.gridLine.opacity(0.3), spacing: 40)  // Grid background
 40→            }
 41→            .ignoresSafeArea()
 42→        )
 43→        .navigationTitle(isEditing ? "Editar Perfil" : "Configuração")
 44→        .navigationBarTitleDisplayMode(.inline)
 45→        .alert("Ops", isPresented: $showError, actions: {
 46→            Button("Ok", role: .cancel) {}
 47→        }, message: {
 48→            Text(viewModel.errorMessage ?? "Algo inesperado aconteceu.")
 49→        })
 50→        .onChange(of: viewModel.errorMessage) { _, newValue in
 51→            showError = newValue != nil
 52→        }
 53→    }
 54→
 55→    private var setupView: some View {
 56→        ScrollView {
 57→            VStack(alignment: .leading, spacing: 20) {
 58→                StepperHeader(
 59→                    title: activeSteps[currentStep].title,
 60→                    step: currentStep + 1,
 61→                    totalSteps: activeSteps.count
 62→                )
 63→                setupOptions(for: activeSteps[currentStep])
 64→                    .animation(.easeInOut, value: currentStep)
 65→
 66→                if viewModel.isSaving || isSubmitting {
 67→                    ProgressView("Salvando perfil...")
 68→                        .frame(maxWidth: .infinity)
 69→                }
 70→
 71→                // Botões de ação
 72→                VStack(spacing: 12) {
 73→                    HStack(spacing: 12) {
 74→                        if currentStep > 0 {
 75→                            Button("Voltar") {
 76→                                currentStep -= 1
 77→                            }
 78→                            .fitSecondaryStyle()
 79→                        }
 80→
 81→                        Button(nextButtonTitle) {
 82→                            handleNext()
 83→                        }
 84→                        .fitPrimaryStyle()
 85→                        .disabled(!canAdvance(for: activeSteps[currentStep]) || viewModel.isSaving)
 86→                    }
 87→                }
 88→            }
 89→        }
 90→        .scrollIndicators(.hidden)
 91→    }
 92→    
 93→    private var nextButtonTitle: String {
 94→        let isLastStep = currentStep == activeSteps.count - 1
 95→        if isEditing {
 96→            return isLastStep ? "Salvar alterações" : "Avançar"
 97→        }
 98→        return isLastStep ? "Criar perfil" : "Avançar"
 99→    }
100→
101→    private func handleNext() {
102→        let isLastStep = currentStep == activeSteps.count - 1
103→
104→        if isLastStep {
105→            isSubmitting = true
106→            Task {
107→                let success = await viewModel.submitFullProfile()
108→                await MainActor.run {
109→                    isSubmitting = false
110→                    if success {
111→                        onFinished()
112→                    }
113→                }
114→            }
115→        } else {
116→            currentStep += 1
117→        }
118→    }
119→
120→    @ViewBuilder
121→    private func setupOptions(for step: SetupStep) -> some View {
122→        switch step {
123→        case .goal:
124→            optionList(FitnessGoal.allCases, selected: viewModel.selectedGoal) { goal in
125→                ViewBuilderOption(
126→                    title: goal.title,
127→                    subtitle: goal.subtitle,
128→                    isSelected: viewModel.selectedGoal == goal
129→                ) {
130→                    viewModel.selectedGoal = goal
131→                }
132→            }
133→        case .structure:
134→            optionList(TrainingStructure.allCases, selected: viewModel.selectedStructure) { structure in
135→                ViewBuilderOption(
136→                    title: structure.title,
137→                    subtitle: structure.subtitle,
138→                    isSelected: viewModel.selectedStructure == structure
139→                ) {
140→                    viewModel.selectedStructure = structure
141→                }
142→            }
143→        case .method:
144→            optionList(TrainingMethod.allCases, selected: viewModel.selectedMethod) { method in
145→                ViewBuilderOption(
146→                    title: method.title,
147→                    subtitle: method.subtitle,
148→                    isSelected: viewModel.selectedMethod == method
149→                ) {
150→                    viewModel.selectedMethod = method
151→                }
152→            }
153→        case .level:
154→            optionList(TrainingLevel.allCases, selected: viewModel.selectedLevel) { level in
155→                ViewBuilderOption(
156→                    title: level.title,
157→                    subtitle: level.subtitle,
158→                    isSelected: viewModel.selectedLevel == level
159→                ) {
160→                    viewModel.selectedLevel = level
161→                }
162→            }
163→        case .health:
164→            VStack(spacing: 12) {
165→                ForEach(HealthCondition.allCases, id: \.self) { condition in
166→                    OptionCard(
167→                        title: condition.title,
168→                        subtitle: condition.subtitle,
169→                        isSelected: viewModel.selectedConditions.contains(condition)
170→                    )
171→                    .onTapGesture {
172→                        viewModel.toggleCondition(condition)
173→                    }
174→                }
175→            }
176→        case .frequency:
177→            let options = [2, 3, 4, 5]
178→            VStack(spacing: 12) {
179→                ForEach(options, id: \.self) { number in
180→                    OptionCard(
181→                        title: "\(number)x por semana",
182→                        subtitle: number >= 4 ? "Maior consistência → resultados mais rápidos" : nil,
183→                        isSelected: viewModel.weeklyFrequency == number
184→                    )
185→                    .onTapGesture {
186→                        viewModel.setFrequency(number)
187→                    }
188→                }
189→            }
190→        }
191→    }
192→
193→    private func canAdvance(for step: SetupStep) -> Bool {
194→        switch step {
195→        case .goal: return viewModel.selectedGoal != nil
196→        case .structure: return viewModel.selectedStructure != nil
197→        case .method: return viewModel.selectedMethod != nil
198→        case .level: return viewModel.selectedLevel != nil
199→        case .health: return true
200→        case .frequency: return viewModel.weeklyFrequency != nil
201→        }
202→    }
203→
204→    @ViewBuilder
205→    private func optionList<T: Hashable>(
206→        _ values: [T],
207→        selected: T?,
208→        builder: @escaping (T) -> ViewBuilderOption
209→    ) -> some View {
210→        VStack(spacing: 12) {
211→            ForEach(values, id: \.self) { value in
212→                let option = builder(value)
213→                OptionCard(
214→                    title: option.title,
215→                    subtitle: option.subtitle,
216→                    isSelected: option.isSelected
217→                )
218→                .onTapGesture(perform: option.action)
219→            }
220→        }
221→    }
222→}
