263→    private func loadData() async {
264→        isLoading = true
265→
266→        // Load saved routines
267→        if let routineRepo = resolver.resolve(SavedRoutineRepository.self) {
268→            do {
269→                savedRoutines = try await routineRepo.listRoutines()
270→            } catch {
271→                #if DEBUG
272→                print("[MyWorkouts] Error loading routines: \(error)")
273→                #endif
274→                savedRoutines = []
275→            }
276→        }
277→
278→        // Load custom workouts
279→        if let workoutRepo = resolver.resolve(CustomWorkoutRepository.self) {
280→            do {
281→                workouts = try await workoutRepo.listTemplates()
282→            } catch {
283→                #if DEBUG
284→                print("[MyWorkouts] Error loading workouts: \(error)")
285→                #endif
286→                workouts = []
287→            }
288→        }
289→
290→        isLoading = false
291→    }
