293→    private func deleteRoutine(_ id: UUID) async {
294→        guard let routineRepo = resolver.resolve(SavedRoutineRepository.self) else { return }
295→
296→        do {
297→            try await routineRepo.deleteRoutine(id)
298→            // Reload to refresh the list
299→            savedRoutines = try await routineRepo.listRoutines()
300→        } catch {
301→            #if DEBUG
302→            print("[MyWorkouts] Error deleting routine: \(error)")
303→            #endif
304→        }
305→    }
306→
307→    private func deleteWorkout(_ id: UUID) async {
308→        guard let workoutRepo = resolver.resolve(CustomWorkoutRepository.self) else { return }
309→
310→        do {
311→            try await workoutRepo.deleteTemplate(id: id)
312→            // Reload to refresh the list
313→            workouts = try await workoutRepo.listTemplates()
314→
315→            // Haptic feedback
316→            let generator = UINotificationFeedbackGenerator()
317→            generator.notificationOccurred(.success)
318→        } catch {
319→            #if DEBUG
320→            print("[MyWorkouts] Error deleting workout: \(error)")
321→            #endif
322→        }
323→    }
324→}
