 11→// 💡 Learn: @Observable substitui ObservableObject para gerenciamento de estado moderno
 12→@MainActor
 13→@Observable final class HealthKitConnectionViewModel {
 14→    private(set) var authorizationState: HealthKitAuthorizationState = .notDetermined
 15→    private(set) var isWorking = false
 16→    private(set) var lastSyncResult: String?
 17→    var errorMessage: ErrorMessage?
 18→
 19→    private let healthKit: any HealthKitServicing
 20→    private let syncService: HealthKitHistorySyncService
 21→
 22→    init(
 23→        healthKit: any HealthKitServicing,
 24→        syncService: HealthKitHistorySyncService
 25→    ) {
 26→        self.healthKit = healthKit
 27→        self.syncService = syncService
 28→    }
 29→    
 30→    func load() {
 31→        Task { await refreshAuthorizationState() }
 32→    }
 33→    
 34→    func connect() async {
 35→        do {
 36→            isWorking = true
 37→            defer { isWorking = false }
 38→
 39→            // HealthKit disponível para todos os usuários (free e PRO)
 40→            try await healthKit.requestAuthorization()
 41→            await refreshAuthorizationState()
 42→        } catch {
 43→            handleError(error)
 44→        }
 45→    }
 46→
 47→    func syncLast30Days() async {
 48→        do {
 49→            isWorking = true
 50→            defer { isWorking = false }
 51→
 52→            // HealthKit disponível para todos os usuários (free e PRO)
 53→            // 1. Sincronizar workouts existentes do FitToday com dados do HealthKit
 54→            let updated = try await syncService.syncLastDays(30)
 55→
 56→            // 2. Importar workouts externos do Apple Health (feitos fora do app)
 57→            let imported = try await syncService.importExternalWorkouts(days: 30)
 58→
 59→            if imported > 0 {
 60→                lastSyncResult = "\(updated) treinos atualizados e \(imported) treinos do Apple Health importados."
 61→            } else {
 62→                lastSyncResult = "\(updated) treinos atualizados com duração/calorias."
 63→            }
 64→        } catch {
 65→            handleError(error)
 66→        }
 67→    }
 68→
 69→    private func refreshAuthorizationState() async {
 70→        let state = await healthKit.authorizationState()
 71→        authorizationState = state
 72→    }
 73→
 74→    // MARK: - Error Handling
 75→
 76→    private func handleError(_ error: Error) {
 77→        #if DEBUG
 78→        print("[Error] \(type(of: self)): \(error.localizedDescription)")
 79→        #endif
 80→
 81→        let mapped = ErrorMapper.userFriendlyMessage(for: error)
 82→        errorMessage = mapped
 83→    }
 84→}
 85→
 86→struct HealthKitConnectionView: View {
 87→    // 💡 Learn: Com @Observable, usamos @State em vez de @StateObject
 88→    @State private var viewModel: HealthKitConnectionViewModel?
 89→    @State private var dependencyError: String?
 90→
 91→    init(resolver: Resolver) {
 92→        if let healthKit = resolver.resolve(HealthKitServicing.self),
 93→           let sync = resolver.resolve(HealthKitHistorySyncService.self) {
 94→            _viewModel = State(initialValue: HealthKitConnectionViewModel(
 95→                healthKit: healthKit,
 96→                syncService: sync
 97→            ))
 98→            _dependencyError = State(initialValue: nil)
 99→        } else {
100→            _viewModel = State(initialValue: nil)
101→            _dependencyError = State(initialValue: "Erro de configuração: serviços de HealthKit não estão registrados.")
102→        }
103→    }
104→    
105→    var body: some View {
106→        Group {
107→            if let error = dependencyError {
108→                DependencyErrorView(message: error)
109→            } else if let viewModel = viewModel {
110→                contentView(viewModel: viewModel)
111→            } else {
112→                ProgressView()
113→            }
114→        }
115→        .background(FitTodayColor.background.ignoresSafeArea())
116→        .navigationTitle("Apple Health")
117→        .navigationBarTitleDisplayMode(.inline)
118→    }
119→
120→    @ViewBuilder
121→    private func contentView(viewModel: HealthKitConnectionViewModel) -> some View {
122→        VStack(alignment: .leading, spacing: FitTodaySpacing.lg) {
123→            VStack(alignment: .leading, spacing: FitTodaySpacing.sm) {
124→                Text("Apple Health")
125→                    .font(FitTodayFont.display(size: 22, weight: .bold))
126→                Text("Conecte para importar duração/calorias e exportar seus treinos concluídos.")
127→                    .font(.system(.subheadline))
128→                    .foregroundStyle(FitTodayColor.textSecondary)
129→            }
130→
131→            StatusCard(state: viewModel.authorizationState)
132→
133→            VStack(spacing: FitTodaySpacing.sm) {
134→                Button("Conectar") {
135→                    Task { await viewModel.connect() }
136→                }
137→                .fitPrimaryStyle()
138→                .disabled(viewModel.isWorking)
139→
140→                Button("Importar últimos 30 dias") {
141→                    Task { await viewModel.syncLast30Days() }
142→                }
143→                .fitSecondaryStyle()
144→                .disabled(viewModel.isWorking || viewModel.authorizationState != .authorized)
145→            }
146→
147→            if let result = viewModel.lastSyncResult {
148→                Text(result)
149→                    .font(.system(.footnote, weight: .medium))
150→                    .foregroundStyle(FitTodayColor.textSecondary)
151→            }
152→
153→            Spacer()
154→        }
155→        .padding()
156→        .task { viewModel.load() }
157→        .errorToast(errorMessage: Binding(
158→            get: { viewModel.errorMessage },
159→            set: { viewModel.errorMessage = $0 }
160→        ))
161→    }
162→}
