176→    private var subtitle: String {
177→        switch state {
178→        case .notAvailable:
179→            return "HealthKit não está disponível neste dispositivo."
180→        case .notDetermined:
181→            return "Toque em Conectar para permitir acesso."
182→        case .denied:
183→            return "Você pode liberar o acesso em Ajustes > Saúde."
184→        case .authorized:
185→            return "Pronto para importar métricas e exportar treinos."
